var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"사실은 어렴풋이 알고 있었어.","JPN":"実はうすうすわかっていた。","ENG":"In truth, I somewhat knew.","TWN":"其實我依稀知道，"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"이번 의뢰는 어딘가에서부터, 어쩌면 처음부터 어긋나 있었다고.","JPN":"この依頼はどこからか、もしかしたら最初から間違っていたって。","ENG":"That something was off about this job... Maybe even from the beginning.","TWN":"這次的委託不知道從某處開始，或許從一開始就偏離正軌。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"허억…… 헉…… 허억……!","JPN":"はぁっ……はっ……はあ……！","ENG":"*Huff* *Gasp!* *Huff…!*","TWN":"呼呼……呼……呼呼……！"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"하아…… 하아……. 드디어 얌전해졌네.","JPN":"はあ……はあ……やっと大人しくなったわね。","ENG":"*Huff... Huff...* So you finally decided to give up, eh?","TWN":"呼呼……呼呼……終於放棄抵抗嗎？"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그쪽도 움직이지 마. 지금부터 생길 수 있는 모든 부상은 당신들이 자초한 거야.","JPN":"そっちも動かないで。ここからは怪我をしてもあなたたちの自業自得よ。","ENG":"Don't you dare move either. Any injuries you sustain from now on are entirely your responsibility.","TWN":"你也別動，現在開始，任何可能產生的傷，都是你們自找的。"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"큭…….","JPN":"くっ……","ENG":"Krr...","TWN":"唔……"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"왜 집까지…… 그러니까, 조직에 증언을…….","JPN":"なんで家まで……つまり、組織に証言したことを……","ENG":"Why... to my house? So... they found out tha─","TWN":"怎麼跑到我家來……意思是作證的事被組織……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WOMAN_EP9HALF_NULL_NULL","text":{"KOREA":"유리야, 유미랑 올라가서 어서 자. 응?","JPN":"ユリ、ユミと一緒に上がって早く寝なさい。ね？","ENG":"Yuri, take Yumi upstairs and go to sleep. Okay, sweetie?","TWN":"悠麗，你和悠美快上去睡覺，嗯？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"왜요? 아빠랑 같이 일하는 사람 아니에요?","JPN":"なんで？　お父さんと一緒に働いてる人じゃないの？","ENG":"But why? Isn't he a policeman too?","TWN":"為什麼？那不是爸爸的同事嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"여보, 유리 안 올려 보냈어? 어서 올려 보내.","JPN":"おい、ユリはまだ上がってないのか？　早く行かせろ。","ENG":"Honey, take Yuri upstairs now.","TWN":"老婆，還不叫悠麗上去？快叫她上去！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"결국 나는 겁쟁이였어.","JPN":"結局私は臆病者だった。","ENG":"I was a coward.","TWN":"結果我是個膽小鬼。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"우리 가족을 이런 꼴로 만든 놈이 저 여자처럼 자기 죄를 후회하고 있다면 어떻게 해야 할지.","JPN":"私の家族をこんな風にしたやつがあの女のように罪を後悔しているとしたら、どうするか。","ENG":"Wondering what I would do if that jerk who had destroyed my family regretted his sins, just like her...","TWN":"我害怕，要是殺害我家人的犯人，和那女人一樣對自己的犯行感到後悔的話怎麼辦，"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"무서워서, 견딜 수 없었던 거야.","JPN":"怖くて、耐えられなかったんだ。","ENG":"I was so terrified, I couldn't stand it.","TWN":"我怕到無法承受。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"알고 있어?","JPN":"知ってる？","ENG":"Did you know about this?","TWN":"你知道嗎？"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"화기로 무장한 중범죄자가 체포에 불응한다면, 제압 과정에서 <color=#ffd34c>피치 못할</color> 사정으로 사살할 수도 있어.","JPN":"火器で武装した重犯罪者が逮捕に応じない場合、制圧する際に<color=#ffd34c>やむを得ない</color>事情で射殺することもできるの。","ENG":"An armed felon who resists arrest may be killed as a result of the arrest's <color=#ffd34c>unfortunate circumstances</color>.","TWN":"武裝份子若不配合被捕，在逮捕過程中，可基於<color=#ffd34c>不可避</color>之情形開槍射殺。"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"내가 지금 손 하나 까딱하면……. 당신 인생은 경위서 한 장으로 바뀌게 되는 거야.","JPN":"私が今指一本動かせば……あなたの人生は経緯報告書一枚で変わっちゃうというわけ。","ENG":"With just the slightest movement of my hand... Your life could end, and all I need to do is file a one-page police report.","TWN":"我現在只要一個手滑……你的人生就會立刻成為一份報告書。"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};